"""FlowState — Executor 내장 논리적 흐름 모델.

PipelineExecutor가 에이전트 모드(LLM 자유 판단)와
플로우 모드(정의된 논리적 흐름)를 모두 처리할 수 있게 한다.

스텝 모델은 mantis.workflow.models.WorkflowStep을 그대로 사용한다.
"""

from __future__ import annotations

import logging
import re
from dataclasses import dataclass, field
from typing import Any

from mantis.workflow.models import WorkflowStep

logger = logging.getLogger(__name__)

# WorkflowStep을 FlowStep으로도 참조 가능 (하위 호환)
FlowStep = WorkflowStep


@dataclass
class FlowState:
    """플로우 실행 상태.

    스텝 목록, 현재 위치, 누적 결과를 관리한다.
    PipelineExecutor._run_flow()가 이 객체를 소비하며 실행을 진행한다.
    """

    steps: list[WorkflowStep]
    current_index: int = 0
    step_results: dict[str, Any] = field(default_factory=dict)
    _skipped: set[str] = field(default_factory=set)

    @property
    def is_done(self) -> bool:
        while (
            self.current_index < len(self.steps)
            and self.steps[self.current_index].id in self._skipped
        ):
            self.current_index += 1
        return self.current_index >= len(self.steps)

    def current_step(self) -> WorkflowStep:
        return self.steps[self.current_index]

    def advance(self, target_step: str | None = None) -> None:
        """다음 스텝으로 이동. target_step이 있으면 해당 스텝으로 점프."""
        if target_step is not None:
            for i, step in enumerate(self.steps):
                if step.id == target_step:
                    self.current_index = i
                    return
            logger.warning("점프 대상 '%s' 없음, 다음 스텝으로 진행", target_step)
        self.current_index += 1

    def skip(self, step_id: str) -> None:
        """특정 스텝을 건너뛰기 대상으로 등록."""
        self._skipped.add(step_id)

    def resolve_args(self, step: WorkflowStep) -> dict[str, Any]:
        """스텝의 args를 해소. args_from이 있으면 이전 결과에서 가져온다."""
        if step.args_from:
            parts = step.args_from.split(".", 1)
            source_id = parts[0]
            source_data = self.step_results.get(source_id, {})

            if len(parts) == 2:
                key = parts[1]
                if isinstance(source_data, dict):
                    return {key: source_data.get(key)}
                return {key: source_data}
            if isinstance(source_data, dict):
                return source_data
            return {"result": source_data}

        return dict(step.args) if step.args else {}

    def evaluate_condition(self, condition: str) -> bool:
        """조건식을 평가. steps.step_id.key 패턴을 실제 값으로 치환."""
        expr = condition

        def _replace(match: re.Match) -> str:
            step_id = match.group(1)
            key = match.group(2)
            data = self.step_results.get(step_id, {})
            if isinstance(data, dict):
                val = data.get(key, "None")
            else:
                val = data
            return repr(val)

        expr = re.sub(r"steps\.(\w+)\.(\w+)", _replace, expr)

        try:
            return bool(eval(expr, {"__builtins__": {}}, {}))  # noqa: S307
        except Exception:
            logger.warning("조건 평가 실패: %s", condition)
            return False

    def evaluate_condition_value(self, condition: str) -> Any:
        """조건식의 값을 반환 (N-way 분기용). steps.step_id.key 패턴을 해소."""
        match = re.match(r"^steps\.(\w+)\.(\w+)$", condition.strip())
        if match:
            step_id = match.group(1)
            key = match.group(2)
            data = self.step_results.get(step_id, {})
            if isinstance(data, dict):
                return data.get(key)
            return data

        # 단순 steps.step_id 참조
        match = re.match(r"^steps\.(\w+)$", condition.strip())
        if match:
            return self.step_results.get(match.group(1))

        # 그 외는 bool 평가로 폴백
        return self.evaluate_condition(condition)


def flow_from_workflow(workflow: Any) -> FlowState:
    """WorkflowDef → FlowState 변환.

    WorkflowDef.steps를 그대로 사용한다 (동일 타입).
    """
    return FlowState(steps=list(workflow.steps))
